static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    const auto *xShape = context->GetInputShape(0);
    const auto *wShape = context->GetInputShape(1);

    // Expect x: [N, Cin, Din, Hin, Win], weight: [Cin, Cout, Kd, Kh, Kw]
    int64_t N   = xShape->GetOriginShape().GetDim(0);
    int64_t Cin = xShape->GetOriginShape().GetDim(1);
    int64_t Din = xShape->GetOriginShape().GetDim(2);
    int64_t Hin = xShape->GetOriginShape().GetDim(3);
    int64_t Win = xShape->GetOriginShape().GetDim(4);

    int64_t CinW = wShape->GetOriginShape().GetDim(0);
    int64_t Cout = wShape->GetOriginShape().GetDim(1);
    int64_t Kd   = wShape->GetOriginShape().GetDim(2);
    int64_t Kh   = wShape->GetOriginShape().GetDim(3);
    int64_t Kw   = wShape->GetOriginShape().GetDim(4);

    // Conservative assumptions: stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1), groups=1.
    int64_t Dout = Din + Kd - 1;
    int64_t Hout = Hin + Kh - 1;
    int64_t Wout = Win + Kw - 1;

    // Basic validations (Cin should match).
    if (CinW != Cin) {
        return ge::GRAPH_FAILED;
    }

    uint64_t totalOutLen64 = static_cast<uint64_t>(N) * static_cast<uint64_t>(Cout) *
                             static_cast<uint64_t>(Dout) * static_cast<uint64_t>(Hout) *
                             static_cast<uint64_t>(Wout);
    if (totalOutLen64 == 0) {
        return ge::GRAPH_FAILED;
    }

    // Simple tiling policy over flattened output length.
    static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024; // per-core UB budget (conservative)
    static constexpr uint32_t ALIGN_ELEMS = 1024;
    uint32_t maxTile = AlignDown(UB_BUDGET_BYTES / sizeof(float) / 2, ALIGN_ELEMS); // 2x safety factor
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t totalOutLen = static_cast<uint32_t>(totalOutLen64);
    uint32_t tileLen = (totalOutLen < maxTile) ? totalOutLen : maxTile;
    if (tileLen > 0) tileLen = AlignDown(tileLen, ALIGN_ELEMS) > 0 ? AlignDown(tileLen, ALIGN_ELEMS) : tileLen;

    const uint32_t numTiles = CeilDiv(totalOutLen, (tileLen == 0 ? 1u : tileLen));
    uint32_t blockDim = numTiles;
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_cin(static_cast<uint32_t>(Cin));
    tiling.set_cout(static_cast<uint32_t>(Cout));
    tiling.set_din(static_cast<uint32_t>(Din));
    tiling.set_hin(static_cast<uint32_t>(Hin));
    tiling.set_win(static_cast<uint32_t>(Win));
    tiling.set_kd(static_cast<uint32_t>(Kd));
    tiling.set_kh(static_cast<uint32_t>(Kh));
    tiling.set_kw(static_cast<uint32_t>(Kw));
    tiling.set_dout(static_cast<uint32_t>(Dout));
    tiling.set_hout(static_cast<uint32_t>(Hout));
    tiling.set_wout(static_cast<uint32_t>(Wout));
    tiling.set_totalOutLen(totalOutLen);
    tiling.set_tileLen(tileLen);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

